Thinking.text:
Now I have a clear picture. Important findings:

1. `handle()` already handles `file_info` (only checks duration). I should NOT let my new `video_info` message reach the engine — it doesn't know about it, so it'll just silently ignore it (the `default` case is not handled, the switch just doesn't match and falls through). So sending `video_info` to `engine.handle()` is safe but wasteful. Better to filter in app.js.

2. `start()` sets up `heartbeatTimer` and `driftTimer` (no video event listeners). So calling start() multiple times is safe (start calls stop() first). 

3. The `driftTimer` only sends drift_check if `!this.video.paused`. So if no video loaded, currentTime=0, paused=true → no sync traffic. But heartbeat WILL still send every 5s. That means in `in_room_no_video` state, we'd send heartbeats. That's not great.

4. So I should defer `engine.start()` to when entering `in_room_synced`. Then `engine.stop()` on leaving. This is cleaner.

5. The existing `file_info` is sent in conn.on('open') which I'm changing to `video_info`.

Plan for app.js integration:

```javascript
// At top
const { STATES, RoomStateMachine } = window.SyncPlayRoomState || {};
const { videosMatch, describeVideo } = window.SyncPlayVideoMatch || {};

// My state
let myVideoInfo = null;   // {url?, fileName?, duration?}
let peerVideoInfo = null; // {url?, fileName?, duration?}

// Room state machine
const roomState = new RoomStateMachine();

// Helper: update my video info and broadcast
function setMyVideoInfo(info) {
  myVideoInfo = info;
  recomputeRoomState();
  if (connMgr && connMgr.send) {
    if (info) {
      connMgr.send({ type: 'video_info', ...info, loaded: true });
    } else {
      connMgr.send({ type: 'video_info', loaded: false });
    }
  }
}

function setPeerVideoInfo(info) {
  peerVideoInfo = info;
  recomputeRoomState();
}

function recomputeRoomState() {
  if (!connMgr) { roomState.setState('no_room'); return; }
  // conn.open is the test for "in room"
  if (!connMgr.conn || !connMgr.conn.open) {
    if (roomState.state === 'no_room') {
      // not yet started
    } else {
      roomState.setState('connecting');
    }
    return;
  }
  // in room
  const myLoaded = !!(myVideoInfo && myVideoInfo.loaded);
  const peerLoaded = !!(peerVideoInfo && peerVideoInfo.loaded);
  if (!myLoaded) {
    roomState.setState('in_room_no_video');
  } else if (!peerLoaded) {
    roomState.setState('in_room_waiting_peer_video');
  } else {
    if (videosMatch(myVideoInfo, peerVideoInfo)) {
      roomState.setState('in_room_synced');
    } else {
      roomState.setState('in_room_mismatch');
    }
  }
}

// State listener: UI updates + engine gating
roomState.onStateChange((newState, oldState) => {
  // UI display
  const display = STATE_DISPLAY[newState];
  if (display) {
    updateLocalStatus(display.localText, display.localClass);
    if (display.remoteText) {
      updateRemoteStatus(display.remoteText, display.remoteClass);
    }
    const localStatusEl = document.getElementById('localStatus');
    if (localStatusEl) {
      localStatusEl.classList.toggle('mismatch-warning', newState === STATES.IN_ROOM_MISMATCH);
    }
  }
  // Engine gating
  if (connMgr && connMgr.engine) {
    if (newState === STATES.IN_ROOM_SYNCED) {
      connMgr.engine.start();
    } else if (oldState === STATES.IN_ROOM_SYNCED) {
      connMgr.engine.stop();
    }
  }
});
